import{_ as e,c as i,G as t,a3 as o,B as r,o as s}from"./chunks/framework.BDUoXecB.js";const k=JSON.parse('{"title":"Slack利用ガイドライン","description":"","frontmatter":{"sidebarDepth":4,"title":"Slack利用ガイドライン","author":"フューチャー株式会社","head":[["meta",{"name":"keywords","content":"Slack"}]]},"headers":[],"relativePath":"documents/forSlack/slack_usage_guidelines.md","filePath":"documents/forSlack/slack_usage_guidelines.md"}'),c={name:"documents/forSlack/slack_usage_guidelines.md"};function n(p,a,d,h,u,b){const l=r("page-title");return s(),i("div",null,[t(l),a[0]||(a[0]=o('<p>本規約は、世の中のシステム開発プロジェクトのために無償で提供致します。<br> ただし、掲載内容および利用に際して発生した問題、それに伴う損害については、フューチャー株式会社は一切の責務を負わないものとします。<br> また、掲載している情報は予告なく変更することがございますので、あらかじめご了承下さい。</p><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><p>リモートワーク／ハイブリッドワーク前提の業務において、チャットなどの非同期コミュニケーションを円滑に進めることは、業務効率を向上させるだけではなく、従業員全員の満足度を向上させ、より良い職場づくりに繋げることができる。</p><p>また、ユーザーの様々な要望に応えるため、現代のチャットサービスは豊富な機能が提供されている。しかし、各ユーザーの考え方／利用者の感覚が千差万別であるため、ある人によって問題ないとされる行動が、別の人にとっては良くない受け取り方をされることも多い。例えば次のような対立が考えられる。</p><ul><li>必要最低限の簡潔なメッセージを送る方が効率的だ／文面が冷たくならないように絵文字や感嘆符（！）を使うべきだ</li><li>質問はDMで行うべき／チャンネルで行うべき</li><li>times（分報）チャンネルを活用すべき／ノイズなので個人のメモに閉じるべき</li></ul><p>これら運用方法は利用者の所属する部署やチームごとに自然と決めていくことが多いが、複数のチャンネルで異なった運用方針である場合に混乱をきたすことがしばしばである。また、トレードオフを理解せずに、メールのコミュニケーションモデルを引きずった方針を取ってしまうこともある。異なる文化圏のチームから移籍した時に、ハレーションが起きるケースも多い。</p><p>本ガイドラインはSlackを対象に利用方針についてのベースとなる規約を設け、Slackを用いてより良いコミュニケーションを促進することを目的とする。</p><h2 id="適用範囲" tabindex="-1">適用範囲 <a class="header-anchor" href="#適用範囲" aria-label="Permalink to &quot;適用範囲&quot;">​</a></h2><ul><li>「はじめに」章で述べた、一般ユーザー視点での利活用を中心とする</li><li>次のような特に管理者が関心を持つ事項については対象外とする <ul><li>パスワードポリシー／多要素認証の強制</li><li>社外メンバー招待／ゲストレベルの調整</li><li>監査</li></ul></li></ul><h2 id="免責事項" tabindex="-1">免責事項 <a class="header-anchor" href="#免責事項" aria-label="Permalink to &quot;免責事項&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">有志で作成したドキュメントである</p><ul><li>フューチャーアーキテクトには多様なプロジェクトが存在し、それぞれの状況に合わせて工夫された運営方針が存在する。本規約はフューチャーアーキテクトの全ての部署／プロジェクトで利用されているわけではなく、有志が観点を持ち寄って新たに整理したものである。相容れない部分があればその領域を書き換えて利用することを想定している</li><li>自社のセキュリティポリシーや外部サービス利用ポリシーがある場合は、そちらを優先すること</li><li>Slack Enterprise Grid／Google Workspaceを利用しているため、それらの機能を前提にしている記述がある</li></ul></div><h2 id="管理者向け推奨設定" tabindex="-1">管理者向け推奨設定 <a class="header-anchor" href="#管理者向け推奨設定" aria-label="Permalink to &quot;管理者向け推奨設定&quot;">​</a></h2><h3 id="workspace-access" tabindex="-1">Workspace Access <a class="header-anchor" href="#workspace-access" aria-label="Permalink to &quot;Workspace Access&quot;">​</a></h3><p>チーム、プロジェクトでの利用の場合は リクエスト制（<code>By Request</code>） もしくは招待性（ <code>Invite Only</code>）の設定を推奨する。</p><h3 id="デフォルトチャンネル" tabindex="-1">デフォルトチャンネル <a class="header-anchor" href="#デフォルトチャンネル" aria-label="Permalink to &quot;デフォルトチャンネル&quot;">​</a></h3><p>通常ワークスペースにメンバーを追加した際には <code>#general</code> へ自動参加するが、他にもメンバー全員に参加して欲しいチャンネルがある場合にはデフォルトチャンネルを追加する。</p><div class="tip custom-block"><p class="custom-block-title">💡ユーザグループに対してもデフォルトチャンネルを設定できるため、用途に応じて使い分けると良い。</p></div><h3 id="表示名ガイドライン" tabindex="-1">表示名ガイドライン <a class="header-anchor" href="#表示名ガイドライン" aria-label="Permalink to &quot;表示名ガイドライン&quot;">​</a></h3><p>ワークスペースごとにガイドラインを設定することを推奨する。後述の表示名設定や、その他チームコミュニケーションにおけるルールを設定する。表示名のガイドラインを設定する権限があるのは、ワークスペースのオーナーだけなので注意する。</p><h3 id="ワークスペースの管理者" tabindex="-1">ワークスペースの管理者 <a class="header-anchor" href="#ワークスペースの管理者" aria-label="Permalink to &quot;ワークスペースの管理者&quot;">​</a></h3><p>ワークスペース内に複数のチームが混在する場合、それぞれのチームごとに管理者権限保持者を設定すること。</p><p>理由:</p><ul><li>管理者権限を持った人しか実行できないオペレーションがあった際、チーム内で解決できる状態を作っておくことが望ましいため</li></ul><h2 id="ユーザ向け推奨設定" tabindex="-1">ユーザ向け推奨設定 <a class="header-anchor" href="#ユーザ向け推奨設定" aria-label="Permalink to &quot;ユーザ向け推奨設定&quot;">​</a></h2><h3 id="アカウントアイコンを設定する" tabindex="-1">アカウントアイコンを設定する <a class="header-anchor" href="#アカウントアイコンを設定する" aria-label="Permalink to &quot;アカウントアイコンを設定する&quot;">​</a></h3><p>デフォルトのアイコン利用は極力避け、アカウント登録時に各自のアイコン画像を積極的に登録する</p><p>理由:</p><ul><li>チャットコミュニケーションにおいて、個人識別におけるアイコン画像の有用性が高いため</li></ul><p>また、GitHub/GitLab、Google Workspace、その他利用サービスも同様のアイコンを利用することで、個人を識別しやすくなる。</p><h3 id="検索性の高い氏名-full-name-を設定する" tabindex="-1">検索性の高い氏名（Full name）を設定する <a class="header-anchor" href="#検索性の高い氏名-full-name-を設定する" aria-label="Permalink to &quot;検索性の高い氏名（Full name）を設定する&quot;">​</a></h3><p>表示名（Display name） もしくは氏名（Full name） にて、ローマ字及び漢字（無ければカタカナ）でのフルネームを登録すること。表示名はチームごとに記載文化や書き方が異なるケースが多いので、本ガイドラインでは氏名に記載することを推奨する。例えば「未来 太郎」の場合、「Taro Mirai (未来 太郎)」という記載を推奨する。</p><p>理由:</p><ul><li>Slackではアカウント名のインクリメンタルサーチが強力である。その際、ローマ字でも漢字でもサジェストされる状態にすることでユーザビリティの向上が期待できるため。</li></ul><h3 id="ユーザーグループの推奨" tabindex="-1">ユーザーグループの推奨 <a class="header-anchor" href="#ユーザーグループの推奨" aria-label="Permalink to &quot;ユーザーグループの推奨&quot;">​</a></h3><p>ユーザーグループの利用を推奨する。ゲストユーザーは追加できないため、もしチャンネルに該当するメンバーが在籍する場合は、その旨をメンバー全員が理解しコミュニケーションから除外してしまわないように注意すること。</p><div class="tip custom-block"><p class="custom-block-title">💡ユーザーグループを作成できない状態の回避策</p><p>ユーザーグループを作成できない状態（メンバーがワークスペース間にまたがっている場合等）の時、メンション先の対象者全員が個別に自分のSlack設定&gt;Notification&gt;My Keywordsに「＠○○チーム」と予約語を登録することで、擬似的にグループメンションが可能である</p></div><h2 id="チャンネル命名規則" tabindex="-1">チャンネル命名規則 <a class="header-anchor" href="#チャンネル命名規則" aria-label="Permalink to &quot;チャンネル命名規則&quot;">​</a></h2><h3 id="外部組織メンバーが在籍するチャンネルの命名" tabindex="-1">外部組織メンバーが在籍するチャンネルの命名 <a class="header-anchor" href="#外部組織メンバーが在籍するチャンネルの命名" aria-label="Permalink to &quot;外部組織メンバーが在籍するチャンネルの命名&quot;">​</a></h3><p>Slack コネクト等でチャンネル内に社外のメンバーが含まれる場合には、チャンネル名の先頭に <code>---ext</code> をつける</p><p>理由:</p><ul><li>全社的に統一的なプレフィックスを定義することで、外部とのコミュニケーションにて予期しないミスが発生してしまうことを防ぐ目的がある。例えば、内部の進行について相談する発言を、取引先メンバーが在籍するチャンネルに誤投稿してしまう事態を避けるため</li><li>チャンネルはセクションという単位でグルーピング可能となり、従来のように、用途や組織を表現するプレフィックスで並び順を制御する必然性が薄れた</li></ul><h2 id="投稿内容ポリシー" tabindex="-1">投稿内容ポリシー <a class="header-anchor" href="#投稿内容ポリシー" aria-label="Permalink to &quot;投稿内容ポリシー&quot;">​</a></h2><h3 id="敬称は不要" tabindex="-1">敬称は不要 <a class="header-anchor" href="#敬称は不要" aria-label="Permalink to &quot;敬称は不要&quot;">​</a></h3><p>敬称は省略して、 <code>@mano メッセージ内容</code> といった形式でコメントすること。もし、どうしても敬称を付けて欲しい場合、表示名をさん付けにするハックも存在するため、受信者側で調整する。</p><p>理由:</p><ul><li>コミュニケーションを迅速・シンプルにするため</li></ul><h3 id="絵文字や感嘆符を活用する" tabindex="-1">絵文字や感嘆符を活用する <a class="header-anchor" href="#絵文字や感嘆符を活用する" aria-label="Permalink to &quot;絵文字や感嘆符を活用する&quot;">​</a></h3><p>積極的に活用することを推奨する。テキストコミュニケーションは、画像や音声が伝わらない分、冷たく捉えられがちである。特にリーダーなど上位のポジションにいる場合は、メンバーに威圧的に捉えられないように配慮するのが好ましい。</p><p>「では、Aの方針でよろしくお願いします！」「では、Aの方針でよろしくお願いします:ganbatte:」 など付けることで、不機嫌でないことがわかり、心理的安全性が保たれる。</p><p>積極的にカスタム絵文字を追加することを推奨する。チーム内でしか通用しない（例えば内輪ネタのような）カスタム絵文字であっても気軽に追加して良い。</p><p>理由:</p><ul><li>より良いコミュニケーション手段を模索すること自体が、コミュニケーションを活性化させ、価値を向上させるため <ul><li>なお、当然ながら他人の名誉を毀損するなど、社会人／プロフェッショナルとしてふさわしくない内容は登録しないこと</li></ul></li></ul><h3 id="絵文字リアクションによる積極応答" tabindex="-1">絵文字リアクションによる積極応答 <a class="header-anchor" href="#絵文字リアクションによる積極応答" aria-label="Permalink to &quot;絵文字リアクションによる積極応答&quot;">​</a></h3><p>非同期のコミュニケーションにおいて発信者が気になる点として、「投稿内容を見てくれたのかどうか」がある。特に確認依頼については見ていればOKで、回答は急がないケースは想像以上に多い。<br> こういった場面では、::後で確認します:: といった絵文字リアクションを付けることで解決するため、積極的に活用する。</p><p>また、参加者が多いチャンネルでの発信は勇気がいることなので、コミュニケーションを活性化させるためにも絵文字リアクションを積極的に行い推奨／礼賛することが望ましい。</p><div class="warning custom-block"><p class="custom-block-title">⚠️「〇〇してほしい」「〇〇について教えてほしい」（相談セクション）への対応は絵文字リアクションだけで済まさない</p><p>「投稿内容を見てくれたのかどうか」ではなく、「投稿内容を理解して次のアクションをとってくれるのか」を知りたい場面も多い。 そのような場面では、絵文字リアクションのみで済まさず、対応可否をコメントでフィードバックする必要がある。</p></div><h3 id="dmはなるべく避ける" tabindex="-1">DMはなるべく避ける <a class="header-anchor" href="#dmはなるべく避ける" aria-label="Permalink to &quot;DMはなるべく避ける&quot;">​</a></h3><p>基本的には、DMよりチャンネルでのやり取りを推奨する。チャンネルであっても、より参加人数が多い（よりオープンな）チャンネルでのやり取りを推奨する。</p><p>理由：</p><ul><li>重複した質問を防ぐため</li><li>質問事項がチーム／組織に共有されることで、全体の効率が上がるため</li><li>後から類似の困りごとを持ったメンバーが、キーワード検索で見つけやすくするため</li></ul><p>DMの利用を推奨するケース:</p><ul><li>人事相談、機密事項を含む場合（「機密情報の流出に注意する」章を参照）</li><li>限られたメンバーのみに、ファイル共有をしたい場合</li><li>後から検索させる意味がないやり取り（「最近元気？」と同期に投げる場合など）</li></ul><h3 id="timesの推奨" tabindex="-1">timesの推奨 <a class="header-anchor" href="#timesの推奨" aria-label="Permalink to &quot;timesの推奨&quot;">​</a></h3><p>timesとは、分報や作業スレッドとも呼ばれ、今取り組んでいることや困っていることを投稿することを指す。</p><p>本規約の推奨は次のとおり:</p><ul><li>timesの利用を推奨する</li><li>メンバーごとのtimesチャンネルではなく、スレッドでの利用を推奨する</li><li>timesスレッドは、他のメンバーは参照しても参照しなくてもどちらでも良い</li></ul><p>理由:</p><ul><li>スレッド単位であれば、本チャンネル側のノイズになることはない。参加メンバーが多い場合は、times専用のチャンネルを作成すれば良い</li><li>メンバーごとの times チャンネルは、チャンネルが必要以上に増えるので推奨しない</li><li>必要に応じて、作業状況を本人に確認（ポーリング）しなくても把握することができる</li><li>ハマったことや調べたことが、後々キーワード検索で見つかり、新規参画者の助けになることも多い</li></ul><div class="warning custom-block"><p class="custom-block-title">⚠️timesスレッドの注意</p><p>times内とはいえ、他の人が不快になるような発言や不適切な利用は避ける（チームメンバーが閲覧可能であることを忘れない）</p></div><div class="tip custom-block"><p class="custom-block-title">timesスレッドでのやり取りにこだわりすぎない</p><ul><li>timesスレッドのコメント数は100以上になることもあり、途中で他メンバーに相談事などでメンションを飛ばすと、呼ばれたメンバーには「該当のスレッドの全コメントをチェックしたほうが良いのか」といった迷いが生じる。そのため、times内ではなく相談は別メッセージに切り出して行うことを推奨する</li><li>なお、timesの投稿を読んで欲しいときは、timesスレッドでメンションしても良い</li><li>timesのメンションを受けたユーザーが、その後の投稿の通知を受け取りたくない場合は、そのスレッドの通知を切ることで対応する</li></ul></div><div class="tip custom-block"><p class="custom-block-title">スレッドのフォローは適当なタイミングで外す（外してもらう）</p><p>timesスレッドでメンションされると、その後にもスレッド内の投稿がメンション先のユーザーに通知が飛び続けてしまうのではないか？という懸念がある。</p><ul><li>該当スレッドの必要に応じてフォローを外せば良いので、上記観点でメンションを行う／行わないの判断は行わなくても良い</li><li>前述の通り、timesのコメントを（全て）読んで欲しい否かでスレッド内でメンションするかどうかを決める</li></ul></div><h3 id="メッセージ-スレッドのトップ-は具体的に書く" tabindex="-1">メッセージ（スレッドのトップ）は具体的に書く <a class="header-anchor" href="#メッセージ-スレッドのトップ-は具体的に書く" aria-label="Permalink to &quot;メッセージ（スレッドのトップ）は具体的に書く&quot;">​</a></h3><p>チャンネルのメッセージ（スレッド先頭の投稿）では、話題を端的に表現する。ただし、返信スレッドの中を確認しないと内容が分からないようなメッセージ（タイトル）は非推奨とする。</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">メッセージ（スレッド先頭の投稿）</th></tr></thead><tbody><tr><td style="text-align:left;">✅推奨例</td><td style="text-align:left;">@mirai チケット #4191 foo bar failed のビルドエラーの解消についての相談です。スタックトレースはスレッド内に記載します</td></tr><tr><td style="text-align:left;">❌非推奨例</td><td style="text-align:left;">レビュー依頼</td></tr></tbody></table><p>なお、メンションはメッセージ（スレッド先頭）に付けるか、返信スレッド内に付けるかは任意とする。</p><p>参考:</p><ul><li><a href="https://techblog.cartaholdings.co.jp/entry/better_slack_communication" target="_blank" rel="noreferrer">Slackで要件を書かずに「質問があります。詳細はスレッドに記載」をやめたほうがいい理由 - CARTA TECH BLOG</a></li><li><a href="https://www.m3tech.blog/entry/2024/12/07/110000" target="_blank" rel="noreferrer">リモートワーク時代を生き抜くAI・機械学習チームの働き方 - エムスリーテックブログ</a></li></ul><h3 id="メッセージのurlを活用する" tabindex="-1">メッセージのURLを活用する <a class="header-anchor" href="#メッセージのurlを活用する" aria-label="Permalink to &quot;メッセージのURLを活用する&quot;">​</a></h3><p>Slackは本来、フロー情報向けのツールである。しかしこれをWikiなどのストック情報向けツールに転記する労力は高く、運用が形骸化しがちである。そのため、例えばあるスレッドで設計方針について議論したのであれば、そのスレッドのURLをコピーして、作業チケットやWikiなどに記載し、トレース可能にするような運用にするチームも良く聞く。本規約もスレッドURLの活用を推奨する。</p><p>なお、決定事項の経緯や議論内容を数年経過したのちに確認することもしばしば発生する。そのため議論があればスレッドを利用し、かつ同一スレッドで複数のテーマを混ぜないことが望ましい。関連議論がいくつかのスレッドに分かれる場合、相互に関連スレッドのURLを投稿しておくと良い。</p><div class="tip custom-block"><p class="custom-block-title">💡Slackにおける情報ストック機能</p><p>Canvas、ブックマーク、ピン留め機能を活用することで、Slack内にてストック情報を取り扱うことも可能である。PJで利用している課題管理サービスのURLを共有したい場合にはブックマーク、PJメンバーに都度参照して欲しい特定のメッセージがある場合にはピン留め、情報量が多く章立てて整理をしたい場合にはCanvas、などといった形でユースケースに合わせて使い分ける。</p></div><h3 id="also-send-to-channelは乱発しない" tabindex="-1">Also send to channelは乱発しない <a class="header-anchor" href="#also-send-to-channelは乱発しない" aria-label="Permalink to &quot;Also send to channelは乱発しない&quot;">​</a></h3><p>Also send to channel を利用することで、スレッド内の投稿をチャンネルのタイムライン側に重複投稿ができる。</p><p>本規約の推奨は以下の通り:</p><ul><li>過去のスレッドでやり取りを再開した場合に、チャンネルに在籍するメンバーに通知する目的で用いる</li><li>スレッド内で重要な決定事項に至った場合は、メンバーに周知する目的で用いる</li><li>スレッド内のやり取りを細かくAlso send to channelすると、スレッドを用いる意味が薄れるので、利用頻度は抑えるように意識する</li></ul><h3 id="広めの通知に注意する" tabindex="-1">広めの通知に注意する <a class="header-anchor" href="#広めの通知に注意する" aria-label="Permalink to &quot;広めの通知に注意する&quot;">​</a></h3><h4 id="channel" tabindex="-1"><code>@channel</code> <a class="header-anchor" href="#channel" aria-label="Permalink to &quot;`@channel`&quot;">​</a></h4><p>緊急時を除き、原則利用を禁止する。</p><p>理由:</p><ul><li><code>@channel</code> はSlackを見ていないユーザにも通知が飛ぶため、休暇中のメンバー等にも影響がある。受取側で制御すべきという考えもあるが、システム障害対応など優先度の高い問い合わせのために、あえてOFFにしていないメンバーも存在することを考えると、なるべく利用を避けた方が無難である</li></ul><p>利用して良い場合:</p><ul><li>システム障害時など、重大かつ緊急度が高い場合は <code>@channel</code> を使っても良い</li></ul><h4 id="here" tabindex="-1"><code>@here</code> <a class="header-anchor" href="#here" aria-label="Permalink to &quot;`@here`&quot;">​</a></h4><p>メールのCCに似た意図で <code>@here</code> を使うことは禁止とする。</p><p>推奨ケース</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@真野 @村田 ○○の件ですが\\~</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>NG（メールのCC的な形で <code>@here</code> を追加）</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@真野 @村田 @here ○○の件ですが</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>理由:</p><ul><li>メールのCC的な参考情報であれば、<code>@here</code> を付けずに、チャンネルの未読通知で後で見ることができるため</li><li>真に必要ではないときに通知が飛ぶことが常態化すると、<code>@here</code> の緊急性やアクションを求める意味合いが弱まり、真に必要なときに読み飛ばされてしまう可能性が上がるため（「狼少年」現象）</li></ul><p>利用して良い場合:</p><ul><li>全員にアクションを促す連絡事項を行う場合。例えば、チーム全体イベントへの出欠可否を確認する連絡など</li></ul><h3 id="メンション範囲は適切に" tabindex="-1">メンション範囲は適切に <a class="header-anchor" href="#メンション範囲は適切に" aria-label="Permalink to &quot;メンション範囲は適切に&quot;">​</a></h3><h4 id="過剰なメンションの抑制" tabindex="-1">過剰なメンションの抑制 <a class="header-anchor" href="#過剰なメンションの抑制" aria-label="Permalink to &quot;過剰なメンションの抑制&quot;">​</a></h4><p>原則、レビュー依頼や確認依頼など、行動してほしい時にメンションを付けるものとする。「@mirai ありがとうございます！」「@mirai 承知しました！」等の挨拶にメンションを付けると、通知が来てノイズになるため非推奨とする。メンションを付けず「ありがとうございます！」とすると良い。</p><div class="tip custom-block"><p class="custom-block-title">💡情報提供依頼系など善意やり取りはきちんとフィードバックする</p><p>情報提供依頼はSlackと親和性が良いタスクである。この際、情報提供の依頼者は、回答してもらった人に対して、👍 絵文字だけのリアクションを取る場合があるが、フィードバック付きでコメントを返すことが望ましい。情報提供者としても、その情報が役立ったのか、またそうでないかの関心は強いためである。<br> もし、フィードバックが難しい場合や、スレッド投稿数をなるべく減らしたいなどの意図がある場合は、複数のリアクションを返し感謝の意を強調すると良い。 👍️🎉☺[神] のようなイメージである。</p></div><h4 id="メンションの宛先をできる限り絞り込む" tabindex="-1">メンションの宛先をできる限り絞り込む <a class="header-anchor" href="#メンションの宛先をできる限り絞り込む" aria-label="Permalink to &quot;メンションの宛先をできる限り絞り込む&quot;">​</a></h4><p>単なる周知目的ではなく行動を促したい相手に絞ること。お見合いになってボールが浮いてしまう可能性がある。「@mirai @mano @murata @ozawa @tanimura AWSの設定で確認したいのですが～」などと広すぎる場合は、宛先メンバーは自分よりもっと詳しい人がいるかも知れないので、回答すべきかどうか逡巡してしまう。できれば1、2名に宛先を絞り、宛先メンバーから別の有識者メンバーにディスパッチしてもらう運用を考えると良い。</p><h3 id="予約投稿を活用する" tabindex="-1">予約投稿を活用する <a class="header-anchor" href="#予約投稿を活用する" aria-label="Permalink to &quot;予約投稿を活用する&quot;">​</a></h3><p>特にリーダーからメンバーに対して、深夜（22:00-6:00など）や休日など業務時間外の投稿は原則禁止とし、予約投稿を推奨する。</p><p>理由:</p><ul><li>仕事とプライベートにメリハリを持たせることで、成果の向上を期待できるため</li><li>（システム障害等）緊急時の依頼と混同してしまうため。次回出勤時の対応で良いものと区別すること</li><li>Slackのアップデートにより、チャンネル投稿に閉じずスレッド投稿へも予約投稿が可能となった</li></ul><div class="tip custom-block"><p class="custom-block-title">💡受け取り側で制御する方針</p><p>システム障害時などの緊急時は電話連絡とし、メンションに対する即対応を求めない取り決めを行うのであれば、受け取り側で通知時間を設定し、送る側は送信時間に気を遣わない運用も可とする。ただし、時間外に通知を受け翌営業日に対応しようと考えたが翌営業日には忘れているような場合、受け取り側で通知を受けた時点でリマインダーを仕込んだり、アクティビティ &gt; @メンション を定期的に確認するような工夫をする。</p></div><h3 id="不在の表明" tabindex="-1">不在の表明 <a class="header-anchor" href="#不在の表明" aria-label="Permalink to &quot;不在の表明&quot;">​</a></h3><p>表示名に不在情報を記載（例：<code>@sato_11/8休</code>）しておくことを推奨する。受信側が不在時に緊急性の低い通知を防げたり、送信側が即レスを期待しなくて済む。不在情報がGoogleカレンダーなど別のスケジュールアプリで管理されていたとしても、Slackでの依頼時に気付けるため。</p><div class="tip custom-block"><p class="custom-block-title">💡ステータス機能で「休暇中🏝️」にすればよいのではないか</p><p>ステータス機能でもチームメンバーに不在であるという状態を表明できる。しかし、次の観点で表示名での表明を推奨する。</p><ul><li>いつから、いつまで休暇なのかステータスでは不明である <ul><li>期間が分かれば、予約投稿で休暇明けに投稿するなどのアクションがすぐ取れる</li></ul></li><li>休暇だけでなく出張中などの情報も提示できる <ul><li>例えば、海外出張なので時差があることが分かれば、チームメンバーにどれくらいでレスポンスが来そうか予想ができるようになる</li></ul></li><li>ステータス変更に気が付きにくい <ul><li>メンションを付けて投稿する時に常時表示されるわけではないので、ステータスは見過ごされる可能性が高い</li></ul></li></ul></div><h3 id="可読性を上げるための書式設定" tabindex="-1">可読性を上げるための書式設定 <a class="header-anchor" href="#可読性を上げるための書式設定" aria-label="Permalink to &quot;可読性を上げるための書式設定&quot;">​</a></h3><p>箇条書き、太字、引用などの装飾は、積極的に活用する。文章を構造化することで、読み手にとっての負荷が軽減されるため。Slackの書式以外にも、【すみかっこ】等の記号を使うことでセクションを表現することも同時に推奨する。</p><h3 id="エラーメッセージの画像添付非推奨、テキストスニペットの推奨" tabindex="-1">エラーメッセージの画像添付非推奨、テキストスニペットの推奨 <a class="header-anchor" href="#エラーメッセージの画像添付非推奨、テキストスニペットの推奨" aria-label="Permalink to &quot;エラーメッセージの画像添付非推奨、テキストスニペットの推奨&quot;">​</a></h3><p>有識者にスタックトレースなどのエラー内容を画像添付して問い合わせることは原則として非推奨とし、テキストで共有することを推奨する。また、共有内容が長文の場合にはテキストスニペット使用が好ましい。</p><p>理由:</p><ul><li>相談相手も裏取りとしてスタックトレースの内容を検索することが多々あるため</li><li>後から同様の困り事を持った人が、キーワード検索で見つけにくくなるため</li><li>長いログをそのまま貼り付けるとスレッドを広く埋め尽くしてしまうが、テキストスニペットを使えば1投稿あたりのデフォルト表示域を制限できる</li></ul><p>次の場合は、スクリーンショットなどの画像で共有しても良い。</p><ul><li>コピーできないエラー表示など、テキストでの情報提供が難しい場合</li><li>（相談相手が、コピー範囲などを独自判断で狭められることを防ぐなどの理由で）スクリーンショットでの共有を希望する場合</li></ul><div class="tip custom-block"><p class="custom-block-title">💡テキストスニペット利用時は、タイトル（ファイル名）に拡張子をつける</p><p>Slackはテキストスニペットに設定されたタイトルをそのままファイル名としてダウンロードするよう動作する。この際拡張子が設定されていないとSlack内でそのままファイルを開くことができなくなってしまう。</p></div><h3 id="機密情報の流出に注意する" tabindex="-1">機密情報の流出に注意する <a class="header-anchor" href="#機密情報の流出に注意する" aria-label="Permalink to &quot;機密情報の流出に注意する&quot;">​</a></h3><p>営業情報、個人情報、人事情報など機密情報は、「最小権限の原則」に従い、なるべく宛先を狭めるべきである。センシティブなやり取りを行う場合は、参加者を絞ったプライベートチャンネル／DMグループの活用を推奨する。</p><div class="tip custom-block"><p class="custom-block-title">💡メッセージ通知にも気をつける</p><p>画面投影やWebミーティングでの画面共有時、意図しないメッセージ通知が見えてしまう事がある。Slackの通知設定にて次に示す設定を施すことで防ぐことが可能なので活用すると良い。</p><ul><li>通知自体をOFFにする</li><li>通知はOFFにしないが、メッセージ内容は非表示にする</li></ul></div><h3 id="ファイルの共有に注意する" tabindex="-1">ファイルの共有に注意する <a class="header-anchor" href="#ファイルの共有に注意する" aria-label="Permalink to &quot;ファイルの共有に注意する&quot;">​</a></h3><p>Slackのファイル共有は便利であるが、ファイルのオーナー（作成者）とチャンネルにメンバー追加できる担当者が必ずしも1:1ではない。そのため次の運用が望ましい。</p><p>推奨する運用:</p><ul><li>Google Driveなどにファイルをアップロードする</li><li>Google Drive側で適切な権限に絞り込む</li></ul><p>理由:</p><ul><li>Google Drive側で権限設定が可能</li><li>Slack上にアップロードされたファイルが、別のチャンネルに再アップロードされて収集がつかなくなるといったケースを防ぎ、統制を図るため</li></ul><p>該当しないケース:</p><ul><li>社外勉強会の登壇資料など、一般に「公開済み／公開予定 」のファイルはアップロードして良い</li></ul><p>Google DriveのURL共有時プレビュー表示について:</p><ul><li>表紙がプレビューされるが、次の理由により問題ないという立場を取る。 <ul><li>プレビュー表示されるのは1枚目（1シート目）であり、通常は表紙ページが見られるのみ</li><li>ファイルが存在すること自体は知られて良い（チャンネルに投稿しているため）と考えられる</li><li>なにか問題があれば、プレビュー表示を行わない操作がSlack上で可能である</li></ul></li></ul><h3 id="プライベートチャンネルの投稿に対する引用" tabindex="-1">プライベートチャンネルの投稿に対する引用 <a class="header-anchor" href="#プライベートチャンネルの投稿に対する引用" aria-label="Permalink to &quot;プライベートチャンネルの投稿に対する引用&quot;">​</a></h3><p>プライベートチャンネルの投稿コメントを、別のチャンネルにURL引用で投稿すると、該当チャンネルの権限を有していないユーザーにも参照権限を与えてしまう。引用時にはセンシティブな内容が含まれていないか確認するよう注意する。</p><h2 id="さいごに" tabindex="-1">さいごに <a class="header-anchor" href="#さいごに" aria-label="Permalink to &quot;さいごに&quot;">​</a></h2><p>本ガイドラインの策定にあたっては、すでにインターネットに公開されているSlack利用ガイドラインや記事等も参照させていただいた。本ガイドラインが皆様のSlack活用をより快適にする一助となれば幸いである。</p><p>参考：</p><ul><li><a href="https://careers.mercari.com/mercan/articles/23325/" target="_blank" rel="noreferrer">メルカリ社内Slack利用ガイドラインを一挙公開しました〜！！#メルカリな日々 | mercan (メルカン)</a> <a href="https://github.com/mercari/mercari-slack-guidelines/blob/master/Slack_Guidelines_Ja.md" target="_blank" rel="noreferrer">mercari-Slack-guidelines/Slack_Guidelines_Ja.md at master</a></li></ul>',144))])}const q=e(c,[["render",n]]);export{k as __pageData,q as default};
